import { Link, useNavigate } from "react-router-dom";
import { useState } from "react";
import "../../styles/auth.css";

export default function RegisterPage() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    fullNames: "",
    idNumber: "",
    gender: "",
    race: "",
    accountType: "",
    address: "",
    email: "",
    contactNumber: "",
    password: "",
    confirmPassword: "",
  });

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      alert("Passwords do not match");
      return;
    }

    const payload = {
      ...formData,
      carDetailsCompleted: false,
      faceVerified: false,
    };

    localStorage.setItem("registeredUser", JSON.stringify(payload));
    alert("Registration successful. Please login.");
    navigate("/login");
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-left">
          <div className="watermark">SR</div>
          <div className="brand-content">
            <h2>SecureRide</h2>
            <p>Create your verified account using your official personal details.</p>
          </div>
          <div className="left-footer">
            <span>About</span><span>FAQ</span><span>Support</span>
          </div>
        </div>

        <div className="auth-right">
          <h1>Create Account</h1>
          <form className="auth-form" onSubmit={handleSubmit}>
            <div className="field"><label>Full Names</label><input name="fullNames" onChange={handleChange} required /></div>
            <div className="field"><label>ID Number</label><input name="idNumber" onChange={handleChange} required /></div>

            <div className="field">
              <label>Gender</label>
              <select name="gender" onChange={handleChange} required>
                <option value="">Select gender</option>
                <option value="female">Female</option><option value="male">Male</option>
              </select>
            </div>

            <div className="field">
              <label>Race</label>
              <select name="race" onChange={handleChange} required>
                <option value="">Select race</option>
                <option value="african">African</option>
                <option value="coloured">Coloured</option>
                <option value="indian_asian">Indian / Asian</option>
                <option value="white">White</option>
                <option value="other">Other</option>
              </select>
            </div>

            <div className="field">
              <label>Account Type</label>
              <select name="accountType" onChange={handleChange} required>
                <option value="">Select account type</option>
                <option value="driver">Driver</option>
                <option value="passenger">Passenger</option>
              </select>
            </div>

            <div className="field"><label>Address</label><input name="address" onChange={handleChange} required /></div>
            <div className="field"><label>Email</label><input name="email" type="email" onChange={handleChange} required /></div>
            <div className="field"><label>Contact Number</label><input name="contactNumber" onChange={handleChange} required /></div>
            <div className="field"><label>Password</label><input name="password" type="password" onChange={handleChange} required /></div>
            <div className="field"><label>Confirm Password</label><input name="confirmPassword" type="password" onChange={handleChange} required /></div>

            <button className="btn-primary" type="submit">Register</button>
          </form>

          <p className="switch-auth">Already have an account? <Link to="/login" className="auth-link">Login</Link></p>
        </div>
      </div>
    </div>
  );
}
